### Extension Basics

Extensions add new functionality to existing types without modifying them or using inheritance.

```dart
extension StringExtensions on String {
  String get reversed => split('').reversed.join();

  String capitalize() {
    if (isEmpty) return this;
    return this[0].toUpperCase() + substring(1);
  }

  int parseInt() => int.parse(this);
}

void main() {
  print('hello'.reversed);    // olleh
  print('hello'.capitalize()); // Hello
  print('42'.parseInt());      // 42
}
```

### Extension Methods

```dart
extension ListExtensions<T> on List<T> {
  T? get firstOrNull => isEmpty ? null : first;

  T? get lastOrNull => isEmpty ? null : last;

  List<T> shuffled() {
    var copy = [...this];
    copy.shuffle();
    return copy;
  }

  Map<int, T> toMap() {
    var map = <int, T>{};
    for (var i = 0; i < length; i++) {
      map[i] = this[i];
    }
    return map;
  }
}

void main() {
  var numbers = [1, 2, 3, 4, 5];
  print(numbers.firstOrNull); // 1
  print([].firstOrNull);      // null
  print(numbers.shuffled());
}
```

### Extensions on Generics

```dart
extension MapExtensions<K, V> on Map<K, V> {
  Map<K, V> merge(Map<K, V> other) {
    return {...this, ...other};
  }

  Map<V, K> swapKeysAndValues() {
    return entries.fold({}, (map, entry) {
      map[entry.value] = entry.key;
      return map;
    });
  }
}

void main() {
  var map1 = {'a': 1, 'b': 2};
  var map2 = {'c': 3};

  print(map1.merge(map2)); // {a: 1, b: 2, c: 3}
  print(map1.swapKeysAndValues()); // {1: a, 2: b}
}
```

### Extension on Enums

```dart
enum Status { pending, active, completed }

extension StatusExtension on Status {
  String get label {
    switch (this) {
      case Status.pending:
        return 'Pending';
      case Status.active:
        return 'Active';
      case Status.completed:
        return 'Completed';
    }
  }

  bool get isActive => this == Status.active;
}

void main() {
  print(Status.active.label);    // Active
  print(Status.pending.isActive); // false
}
```

### Extension vs Static Helper

| Aspect | Extension | Static Helper |
|--------|-----------|---------------|
| Syntax | `obj.method()` | `Helper.method(obj)` |
| Readability | More natural | Less natural |
| Namespace | On the type | In a class |
| Discovery | IDE suggests | Must import |

> **Key Point:** Extensions add methods to existing types with natural calling syntax. They are resolved statically at compile time based on the static type.

codeExample:
extension NumberParsing on String {
  int toInt() => int.parse(this);
  double toDouble() => double.parse(this);
  bool isNumeric() => double.tryParse(this) != null;
}

extension DurationExtensions on int {
  Duration get seconds => Duration(seconds: this);
  Duration get minutes => Duration(minutes: this);
  Duration get hours => Duration(hours: this);
}

void main() {
  print('42'.toInt() + 8); // 50
  print('3.14'.toDouble()); // 3.14
  print('abc'.isNumeric()); // false

  // Using duration extensions
  Future.delayed(2.seconds, () => print('2 seconds passed'));
  print('Sleep for ${5.minutes.inSeconds} seconds');
}
